#!/usr/bin/env bash
# workflow-4.sh — 并发症识别与急救（不可软化） SOP walkthrough for 医疗美容.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="医疗美容"
WORKFLOW="并发症识别与急救（不可软化）"

usage() {
  cat <<EOF
workflow-4.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./workflow-4.sh             # interactive
  ./workflow-4.sh --dry-run
  ./workflow-4.sh --json
  ./workflow-4.sh --explain
  ./workflow-4.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "并发症识别与急救（不可软化）" 工作流。

一句话: 从「注射中/后出现栓塞、坏死、中毒、感染、结节征象」到「按共识/指南即刻处理、溶解、转诊，最大限度保住组织或视力」——医美最凶险、绝不能软化为「零风险」的 workflow。

入门 SOP 共 6 步, 失败模式自检 4 项。

相关心智模型:
  • 医美的第一性是医疗，不是消费: 医疗美容首先是外科与皮肤科的**医疗行为**（可致盲、致残、致死），不是快消品；任何决策的第一约束是安全与合规，不是美学最大化或转化率。
  • 先安全后审美：风险分层判断: 资深人的核心能力不是「打得漂亮」，而是**在安全处提效、在危险处零妥协**——知道哪一步能省、哪一步一步都不能省。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**血管栓塞即刻处理**：怀疑栓塞立即**停针**；**24h 内（越早越好、把握 ~72h 组织耐缺血窗）大剂量透明质酸酶溶解**（栓塞处及波及远端，超声引导下交联 HA 栓子平均 35–60U、少数达 150U；可重复多次注射）；辅以热敷/硝酸甘油软膏改善循环。 evidence: [T03-S004, T03-S007, T03-S017]"
  "**栓塞致盲急救**：出现视力障碍立即按致盲急救流程——眼科急会诊/转诊、球后或栓塞血管直接注射透明质酸酶、糖皮质激素、降眼压、高压氧抢救存活视网膜组织（**致盲多不可逆，强调争分夺秒**）。 evidence: [T03-S017, T03-S008]"
  "**再生类/脂肪栓塞警示**：透明质酸酶**只对玻尿酸有效**，对 PLLA/PCL/自体脂肪栓塞**无法溶解**——这是再生类/脂肪安全性逊于玻尿酸的关键，处理以血管再通/支持治疗为主，预后更差。 evidence: [T03-S004]"
  "**肉毒扩散/中毒识别**：上睑下垂、面具脸、吞咽/呼吸困难（严重需急诊），多为剂量/点位致扩散，部分可待代谢恢复，重者支持治疗+急诊。 evidence: [T03-S009]"
  "**感染/结节/肉芽肿/丁达尔处理**：感染按抗感染；结节区分可揉散/溶解 vs 肉芽肿（免疫性，激素/手术，难处理）；丁达尔（过浅）用透明质酸酶溶解纠正。 evidence: [T03-S009]"
  "**转诊与修复**：超出本机构/本人能力（致盲、大面积坏死、复杂修复）立即转诊上级/有能力机构，不硬扛。"
)
declare -a FAILURE_MODES=(
  "**错过 24h 溶解窗口**：actionable—注射后任何剧痛/苍白/视力异常立即按栓塞处理，不要「先观察看看」。"
  "**把再生类/脂肪栓塞当玻尿酸溶解**：actionable—对非 HA 栓塞别等溶解酶，直接走血管再通/支持/转诊。"
  "**不转诊硬扛致盲/大面积坏死**：actionable—超能力范围立即转上级 + 眼科/急诊，黑医美最致命的是不会救也不转。"
  "**迟发肉芽肿当普通结节挤压**：加重免疫反应，须区分处理。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "workflow-4-walkthrough"
fi
